noncompliant:
// Noncompliant: Secure flag not set
var cookie = new HttpCookie("SessionId", sessionId);
Response.Cookies.Add(cookie);

// Noncompliant: Explicitly set to false
var cookie = new HttpCookie("SessionId", sessionId)
{
    Secure = false
};
Response.Cookies.Add(cookie);

compliant:
// Compliant: Secure flag set to true
var cookie = new HttpCookie("SessionId", sessionId)
{
    Secure = true
};
Response.Cookies.Add(cookie);

// Compliant: ASP.NET Core with Secure
Response.Cookies.Append("SessionId", sessionId, new CookieOptions
{
    Secure = true,
    HttpOnly = true
});
